class CancipButtonEditModal extends Modal {
  private nameInput: HTMLInputElement | null = null;
  private iconInput: HTMLInputElement | null = null;
  private verifyEl: HTMLElement | null = null;
  private verifyTimer: number | null = null;
  private addCommandSelect: HTMLSelectElement | null = null;
  private addNameInput: HTMLInputElement | null = null;
  private addCommandOptions: UiButtonCommandOption[] = [];
  private addIconButtons: HTMLButtonElement[] = [];
  private selectedAddIcon = "zap";
  private hidden = false;
  private buttonScope: UiButtonRule["scope"];

  constructor(
    app: App,
    private readonly plugin: CancipPlugin,
    private readonly descriptor: UiButtonEditDescriptor,
    private readonly onSendToCancip: () => void | Promise<void>
  ) {
    super(app);
    this.buttonScope = descriptor.rule?.scope ?? descriptor.scope;
    this.hidden = Boolean(descriptor.rule?.hidden);
  }

  onOpen(): void {
    this.modalEl.addClass("obcc-button-edit-modal");
    this.setTitle(this.plugin.t("buttonEditTitle"));
    const topActions = this.contentEl.createDiv({ cls: "obcc-button-edit-sticky-actions" });
    const saveTop = topActions.createEl("button", { text: this.plugin.t("buttonEditSave"), attr: { type: "button" } });
    saveTop.addClass("mod-cta");
    saveTop.addEventListener("click", () => {
      void this.saveRule();
    });

    this.contentEl.createDiv({
      cls: "obcc-button-edit-target",
      text: this.descriptor.label || this.descriptor.selector
    });
    this.contentEl.createDiv({
      cls: "obcc-button-edit-selector",
      text: this.descriptor.selector
    });
    this.verifyEl = this.contentEl.createDiv({ cls: "obcc-button-edit-verify" });
    this.refreshVerifyStatus();
    this.verifyTimer = window.setInterval(() => this.refreshVerifyStatus(), 700);

    new Setting(this.contentEl)
      .setName(this.plugin.t("buttonEditName"))
      .addText((text) => {
        this.nameInput = text.inputEl;
        text.setValue(this.descriptor.rule?.title ?? this.descriptor.label);
        text.setPlaceholder(this.descriptor.label);
      });

    new Setting(this.contentEl)
      .setName(this.plugin.t("buttonEditIcon"))
      .addText((text) => {
        this.iconInput = text.inputEl;
        text.setValue(this.descriptor.rule?.icon ?? "");
        text.setPlaceholder("settings, history, bot, shield-check");
      });

    new Setting(this.contentEl)
      .setName(this.plugin.t("buttonEditSort"))
      .setDesc(this.plugin.t("buttonEditSortDesc"))
      .addButton((button) => {
        button
          .setIcon("grip-vertical")
          .setTooltip(this.plugin.t("buttonEditSort"))
          .onClick(() => {
            this.close();
            this.plugin.startUiButtonSortMode(this.descriptor);
          });
      });

    new Setting(this.contentEl)
      .setName(this.plugin.t("buttonEditHidden"))
      .addToggle((toggle) => {
        toggle.setValue(this.hidden);
        toggle.onChange((value) => {
          this.hidden = value;
        });
      });

    new Setting(this.contentEl)
      .setName(this.plugin.t("buttonEditScope"))
      .addDropdown((dropdown) => {
        dropdown
          .addOption("active", this.plugin.t("buttonEditScopeActive"))
          .addOption("cancip", this.plugin.t("buttonEditScopeCancip"))
          .addOption("global", this.plugin.t("buttonEditScopeGlobal"))
          .setValue(this.buttonScope)
          .onChange((value) => {
            this.buttonScope = value === "active" || value === "cancip" ? value : "global";
          });
      });

    new Setting(this.contentEl)
      .setName(this.plugin.t("buttonEditRevealHidden"))
      .setDesc(this.plugin.t("buttonEditRevealHiddenDesc"))
      .addToggle((toggle) => {
        toggle.setValue(this.plugin.isUiButtonHiddenRevealEnabled());
        toggle.onChange((value) => {
          this.plugin.setUiButtonHiddenReveal(value);
        });
      });

    this.renderAddSiblingSection();

    const actions = this.contentEl.createDiv({ cls: "obcc-button-edit-actions" });
    const copy = actions.createEl("button", { text: this.plugin.t("buttonEditCopyInfo"), attr: { type: "button" } });
    copy.addEventListener("click", () => {
      void this.copyButtonInfo();
    });

    if (this.descriptor.rule) {
      const remove = actions.createEl("button", { text: this.plugin.t("buttonEditRemove"), attr: { type: "button" } });
      remove.addClass("mod-warning");
      remove.addEventListener("click", () => {
        void this.plugin.removeUiButtonRule(this.descriptor.rule?.id ?? "").then(() => {
          new Notice(this.plugin.t("buttonEditRemoved"));
          this.close();
        });
      });
    }
  }

  onClose(): void {
    if (this.verifyTimer !== null) {
      window.clearInterval(this.verifyTimer);
      this.verifyTimer = null;
    }
    this.contentEl.empty();
  }

  private refreshVerifyStatus(): void {
    if (!this.verifyEl) return;
    const status = this.plugin.uiButtonEditTargetStatus(this.descriptor);
    this.verifyEl.empty();
    this.verifyEl.toggleClass("is-ok", status.verified);
    this.verifyEl.toggleClass("is-mismatch", !status.verified);
    const text = status.verified
      ? this.plugin.t("buttonEditVerifyOk", {
          label: status.expectedLabel,
          selectorCount: String(status.selectorCount),
          labelCount: String(status.labelCount)
        })
      : this.plugin.t("buttonEditVerifyMismatch", {
          label: status.expectedLabel,
          selectorCount: String(status.selectorCount),
          labelCount: String(status.labelCount),
          seen: status.seenLabels.join(" / ") || "-"
        });
    this.verifyEl.setText(text);
  }

  private async saveRule(): Promise<void> {
    const title = this.nameInput?.value.trim() || "";
    const icon = this.iconInput?.value.trim() || "";
    const order = this.descriptor.rule?.order ?? 0;
    const selector = this.descriptor.selector;
    const id = this.descriptor.rule?.id ?? stableRuleId(uiButtonRuleStableIdInput(this.buttonScope, selector, this.descriptor.label || selector));
    await this.plugin.upsertUiButtonRule({
      id,
      selector,
      label: this.descriptor.label || selector,
      hidden: this.hidden,
      order,
      title: title && title !== this.descriptor.label ? title : undefined,
      icon: icon || undefined,
      scope: this.buttonScope
    });
    new Notice(this.plugin.t("buttonEditSaved"));
    this.close();
  }

  private async copyButtonInfo(): Promise<void> {
    const payload = this.plugin.uiButtonClipboardPayload(this.descriptor);
    if (!payload) {
      new Notice(this.plugin.t("buttonEditPasteInvalid"));
      return;
    }
    const text = JSON.stringify(payload);
    const copied = await copyTextToClipboard(text, this.plugin.t("buttonEditCopiedInfo"), (key, vars) => this.plugin.t(key, vars));
    if (!copied) await promptTextModal(this.app, this.plugin.t("buttonEditCopyInfoPrompt"), text);
  }

  private renderAddSiblingSection(): void {
    const details = this.contentEl.createEl("details", { cls: "obcc-button-edit-add-section" });
    details.createEl("summary", { cls: "obcc-button-edit-section-title", text: this.plugin.t("buttonEditAddSiblingTitle") });
    let rendered = false;
    const renderBody = () => {
      if (rendered) return;
      rendered = true;
      const section = details.createDiv({ cls: "obcc-button-edit-add-body" });
      section.createDiv({ cls: "obcc-button-edit-section-desc", text: this.plugin.t("buttonEditAddSiblingDesc") });

      this.addCommandOptions = this.descriptor.preloadedCommandOptions ?? this.plugin.uiButtonCommandOptions();
      this.selectedAddIcon = this.addCommandOptions[0]?.icon ?? "zap";
      new Setting(section)
        .setName(this.plugin.t("buttonEditAddCommand"))
        .addDropdown((dropdown) => {
          this.addCommandSelect = dropdown.selectEl;
          for (const option of this.addCommandOptions) {
            dropdown.addOption(option.id, `${option.name} · ${option.id}`);
          }
          const first = this.addCommandOptions[0];
          if (first) dropdown.setValue(first.id);
          dropdown.onChange((value) => {
            const option = this.addCommandOptions.find((item) => item.id === value);
            if (!option) return;
            if (this.addNameInput && !this.addNameInput.value.trim()) this.addNameInput.value = option.name;
            this.setSelectedAddIcon(option.icon);
          });
        });

      new Setting(section)
        .setName(this.plugin.t("buttonEditAddName"))
        .addText((text) => {
          this.addNameInput = text.inputEl;
          const first = this.addCommandOptions[0];
          text.setPlaceholder(first?.name ?? this.plugin.t("buttonEditAddName"));
        });

      section.createDiv({ cls: "obcc-button-edit-section-title", text: this.plugin.t("buttonEditAddIcon") });
      const iconGrid = section.createDiv({ cls: "obcc-button-icon-grid" });
      for (const icon of this.plugin.uiButtonIconOptions()) {
        const button = iconGrid.createEl("button", {
          cls: "obcc-button-icon-choice",
          attr: { type: "button", title: icon, "aria-label": icon }
        });
        setIcon(button, icon);
        button.addEventListener("click", () => this.setSelectedAddIcon(icon));
        this.addIconButtons.push(button);
      }
      this.refreshAddIconButtons();

      const addActions = section.createDiv({ cls: "obcc-button-edit-actions" });
      const paste = addActions.createEl("button", { text: this.plugin.t("buttonEditPasteInfo"), attr: { type: "button" } });
      paste.addEventListener("click", () => {
        void this.pasteSiblingButton();
      });
      const add = addActions.createEl("button", { text: this.plugin.t("buttonEditAddSibling"), attr: { type: "button" } });
      add.addClass("mod-cta");
      add.addEventListener("click", () => {
        void this.addSiblingButton();
      });
    };
    details.addEventListener("toggle", () => {
      if (details.open) renderBody();
    });
    if (details.open) renderBody();
  }

  private async addSiblingButton(): Promise<void> {
    const commandId = this.addCommandSelect?.value.trim() ?? "";
    const option = this.addCommandOptions.find((item) => item.id === commandId);
    if (!commandId || !option) {
      new Notice(this.plugin.t("buttonEditNoCommand"));
      return;
    }
    const title = this.addNameInput?.value.trim() || option.name;
    const icon = this.selectedAddIcon || option.icon || "zap";
    await this.plugin.addSiblingUiButton(this.descriptor, {
      commandId,
      commandName: option.name,
      title,
      icon
    });
    new Notice(this.plugin.t("buttonEditAddedSibling"));
    this.close();
  }

  private async pasteSiblingButton(): Promise<void> {
    const raw = (await readClipboardText()).trim();
    let payload = parseUiButtonClipboardPayload(raw);
    if (!payload) {
      const manual = await promptTextModal(this.app, this.plugin.t("buttonEditPasteInfoPrompt"), raw);
      payload = parseUiButtonClipboardPayload(manual ?? "");
    }
    if (!payload) {
      new Notice(this.plugin.t("buttonEditPasteInvalid"));
      return;
    }
    await this.plugin.addSiblingUiButton(this.descriptor, {
      commandId: payload.commandId,
      commandName: payload.commandName || payload.label || payload.commandId,
      title: payload.title || payload.label || payload.commandName || payload.commandId,
      icon: payload.icon || guessUiButtonCommandIcon(payload.commandId, payload.commandName || payload.label),
      fallbackSelector: payload.fallbackSelector,
      insertPosition: payload.insertPosition
    });
    new Notice(this.plugin.t("buttonEditAddedSibling"));
    this.close();
  }

  private setSelectedAddIcon(icon: string): void {
    this.selectedAddIcon = icon || "zap";
    this.refreshAddIconButtons();
  }

  private refreshAddIconButtons(): void {
    for (const button of this.addIconButtons) {
      button.toggleClass("is-selected", button.getAttribute("aria-label") === this.selectedAddIcon);
    }
  }
}

