function capabilityPromptMentionsWebDocs(text: string): boolean {
  return /(docs|documentation|api|internet|web|online|latest|unknown|文档|资料|网页|网络|联网|最新|不知道|查资料|官网|怎么用)/i.test(text);
}

function capabilityCommandQuery(text: string): string {
  const lower = text.toLowerCase();
  if (/file|文件|open|打开/.test(lower)) return "file";
  if (/plugin|插件/.test(lower)) return "plugin";
  if (/workspace|tab|leaf|工作区|标签/.test(lower)) return "workspace";
  if (/pdf/.test(lower)) return "pdf";
  if (/search|find|搜索|查找/.test(lower)) return "search";
  return "";
}

function capabilityWebSearchQuery(prompt: string): string {
  const cleaned = prompt.replace(/\s+/g, " ").trim();
  if (!cleaned) return "";
  return trimContext(cleaned, 120);
}

function discoveryVaultPathCandidates(userPrompt: string, modelAnswer = ""): string[] {
  const fromUser = extractVaultPathCandidates(userPrompt);
  const fromAnswer = extractVaultPathCandidates(modelAnswer).filter(isLikelyConcreteVaultPath);
  return uniqueStrings([...fromUser, ...fromAnswer]).slice(0, 8);
}

function extractVaultPathCandidates(input: string): string[] {
  const candidates = new Set<string>();
  const normalized = input.replace(/\\/g, "/");
  const configDirPattern = escapeRegExp(OBSIDIAN_CONFIG_FALLBACK);
  const patterns = [
    /(^|[\s"'`([{，。；,;：:])((?:\.?[A-Za-z0-9_\-\u4e00-\u9fff]+\/)+[A-Za-z0-9_\-\u4e00-\u9fff @()[\].]+)(?=$|[\s"'`)\]}，。；,;])/g,
    new RegExp(`(^|[\\s"'\\\`([{，。；,;：:])((?:${configDirPattern}|\\.cancip)(?:/[^\\s"'\\\`)\\]}，。；,;]+)*)`, "gi")
  ];
  for (const pattern of patterns) {
    let match: RegExpExecArray | null;
    while ((match = pattern.exec(normalized)) !== null) {
      const raw = (match[2] ?? "").trim().replace(/[，。；,;:：]+$/, "");
      if (!raw || raw === "." || raw === "..") continue;
      try {
        candidates.add(normalizeActionPath(raw));
      } catch {
        // Ignore non-vault paths such as URLs or drive-letter paths.
      }
    }
  }
  return [...candidates].slice(0, 8);
}

function isLikelyConcreteVaultPath(path: string): boolean {
  const normalized = normalizePath(path);
  if (normalized.startsWith(OBSIDIAN_CONFIG_FALLBACK) || normalized.startsWith(".cancip")) return true;
  const last = normalized.split("/").filter(Boolean).pop() ?? "";
  if (/\.[A-Za-z0-9]{1,8}$/.test(last)) return true;
  return normalized.split("/").length >= 3;
}

function shouldUseDetailedToolProtocol(prompt: string): boolean {
  return /(完整工具协议|详细工具协议|工具协议|动作格式|action format|tool protocol|cancip-action|command bus|命令总线|payload|上下文发送|系统提示词|system prompt|prompt audit|调试提示|debug prompt|debug protocol)/i.test(prompt);
}

function lightweightImplementationPrompt(prompt: string): boolean {
  return !isExecutableTtsPrompt(prompt)
    && /(继续|看看|分析|为什么|原因|状态|情况|查|搜|读取|打开|总结)/i.test(prompt)
    && !/(改|写|修|删|移动|安装|重启|构建|发布|push|release)/i.test(prompt);
}

function isSimpleSingleStepStateChangePrompt(prompt: string): boolean {
  const text = prompt.trim();
  if (!text) return false;
  const compact = text.toLowerCase().replace(/[\s，。！？!?.、~～"'`]+/g, "");
  if (text.length > 180) return false;
  if (/(然后|再|同时|并且|顺便|多个|几个|批量|整理|重构|审核|插件|设置|配置|自动化|github|release|push|构建|重启|修复|优化|排错|分析|对齐|查看|检查)/i.test(compact)) return false;
  if (isExecutableTtsPrompt(text)) return true;
  if (looksLikeCreateVaultFilePrompt(text)) return true;
  return /(新建|创建|建立|生成|写入|保存|create|write|make|new).{0,20}(\.md|md|markdown|笔记|文件)/i.test(text);
}

function shouldCreateProgrammaticPlan(prompt: string): boolean {
  const text = prompt.trim();
  if (!text || isTrivialChatPrompt(text) || isSimpleSingleStepStateChangePrompt(text)) return false;
  if (!promptRequiresStateChange(text) && !shouldUseCapabilityDiscovery(text)) return false;
  const signals = [
    text.length > 80,
    /(修复|优化|排错|改造|完善|对齐|同步|重构|测试|验证|安装|构建|重启|发布|上传|release|push|repair|optimi[sz]e|debug|refactor|test|verify|build|reload)/i.test(text),
    /(插件|配置|设置|审核|面板|侧边栏|状态栏|输入框|弹窗|菜单|skill|mcp|command|命令|自动化|github|tts|pdf|附件)/i.test(text),
    /(并且|同时|顺便|然后|再|多个|几个|批量|整体|通用|举一反三|根本|机制)/i.test(text)
  ].filter(Boolean).length;
  return signals >= 2;
}

function promptNeedsCurrentFileContext(prompt: string): boolean {
  return /(当前文件|当前笔记|这个文件|这个笔记|此文件|此笔记|正在打开|光标|选区|选择的|选中的|selection|cursor|current file|active file|this file|this note)/i.test(prompt);
}

function pluginMemoryCommandQuery(prompt: string): string {
  const lower = prompt.toLowerCase();
  if (lower.includes("file") || prompt.includes("文件")) return "file";
  if (lower.includes("spaced") || lower.includes("repetition") || lower.includes("flashcard") || lower.includes("srs") || prompt.includes("间隔重复") || prompt.includes("复习") || prompt.includes("卡片") || prompt.includes("闪卡")) return "spaced repetition flashcard review";
  if (lower.includes("pdftion") || lower.includes("pdf") || prompt.includes("批注") || prompt.includes("标注")) return "pdftion pdf annotation highlight";
  if (lower.includes("notedraw") || lower.includes("notdraw") || prompt.includes("涂鸦") || prompt.includes("高亮") || prompt.includes("画笔")) return "notedraw draw highlight";
  if (lower.includes("excalidraw")) return "excalidraw";
  if (lower.includes("canvas") || prompt.includes("画布")) return "canvas";
  if (lower.includes("workspace") || prompt.includes("窗口") || prompt.includes("标签")) return "workspace";
  if (lower.includes("tts") || prompt.includes("朗读")) return "tts";
  return "";
}

function detailedRuleRoutingTokens(prompt: string): string {
  const tokens: string[] = [];
  if (promptRequiresStateChange(prompt)) tokens.push("Execution loop", "Permission model", "write", "verify", "approval");
  if (promptMentionsCancip(prompt)) tokens.push("Cancip", "self-repair", "permission", "review", "prompt", "context");
  if (capabilityPromptMentionsAttachmentOrExternalFile(prompt)) tokens.push("Attachments", "parsers", "PDF", "Excel", "external files");
  if (capabilityPromptMentionsObsidianCommand(prompt) || capabilityPromptMentionsPluginSurface(prompt)) tokens.push("Obsidian commands", "plugins");
  if (capabilityPromptMentionsSkillOrExperienceSurface(prompt) || promptNeedsSkillExperienceRoute(prompt)) tokens.push("Skills", "MCP", "memory", "experience", "workflow", "self-optimization");
  if (capabilityPromptMentionsAutomation(prompt)) tokens.push("automation", "schedule");
  if (capabilityPromptMentionsGithub(prompt)) tokens.push("GitHub");
  if (/审核|review|指正|通过|取消|批准|拒绝/i.test(prompt)) tokens.push("review", "approval", "backup");
  if (/tts|朗读|语音/i.test(prompt)) tokens.push("TTS");
  if (/输出|结论|推荐|按钮|折叠|显示/i.test(prompt)) tokens.push("User-facing output", "Recommendation");
  return tokens.join(" ");
}

function shouldShowLocalFallbackHits(prompt: string): boolean {
  return shouldAutoSearchForPrompt(prompt);
}

function shouldSuppressToolActionsForPrompt(prompt: string): boolean {
  const text = prompt.trim();
  if (!text) return true;
  if (extractMentionTokens(text).length) return false;
  if (looksLikePathQuery(text)) return false;
  if (looksLikeCreateVaultFilePrompt(text)) return false;
  const lower = text.toLowerCase();
  if (/(search|find|read|open|summari[sz]e|index|rag|vault|note|file|folder|config|plugin|github|command|run|execute|write|edit|patch|delete|move|rename|create|generate|fix|repair|format|polish|button|style|css|ui|self|查|搜|找|读取|打开|总结|索引|笔记|文件|文件夹|配置|插件|仓库|命令|执行|运行|写|改|修|删|移动|重命名|新建|创建|建立|生成|美化|排版|格式化|润色|按钮|样式|界面|自己|自身|自修)/.test(lower)) {
    return false;
  }
  return false;
}

function isContinuePrompt(prompt: string): boolean {
  const compact = prompt.trim().toLowerCase().replace(/[\s，。！？!?.、~～]+/g, "");
  return /^(继续|继续修|继续做|接着|接着来|接着做|接着修|往下|往下做|下一步|继续吧|继续呀|继续啊|continue|goon|next|proceed|keepgoing)$/.test(compact);
}

function isTrivialChatPrompt(prompt: string): boolean {
  const compact = prompt.trim().toLowerCase().replace(/[\s，。！？!?.、~～]+/g, "");
  return compact === "";
}

function shouldExpectToolActionForPrompt(prompt: string): boolean {
  return classifyPromptIntent(prompt) === "implementation";
}

function classifyPromptIntent(prompt: string): PromptIntent {
  const text = prompt.trim();
  if (!text) return "trivial";
  if (isTrivialChatPrompt(text) || shouldSuppressToolActionsForPrompt(text)) return "trivial";
  if (isImplementationChangePrompt(text)) return "implementation";
  if (isInformationSeekingPrompt(text) || extractMentionTokens(text).length || looksLikePathQuery(text)) return "informational";
  if (shouldAutoSearchForPrompt(text)) return "informational";
  return "trivial";
}

function isImplementationChangePrompt(prompt: string): boolean {
  const compact = prompt.trim().toLowerCase().replace(/[\s，。！？!?.、~～"'`]+/g, "");
  if (!compact) return false;
  if (isExecutableTtsPrompt(prompt)) return true;
  if (looksLikeMemoryWritePrompt(prompt)) return true;
  if (looksLikeCreateVaultFilePrompt(prompt)) return true;
  return /(add|implement|fix|repair|change|modify|update|delete|move|rename|create|install|restart|verify|build|execute|run|close|hide|show|sort|pin|unpin|patch|write|format|polish|optimi[sz]e|debug|troubleshoot|restore|rollback|hot.?patch|notworking|broken|failed|failure|bug|error|stuck|加|新增|添加|补|改|修改|更新|修|修复|删|删除|移动|重命名|新建|创建|安装|装好|重启|验证|构建|执行|运行|打开|开启|关闭|关掉|隐藏|显示|排序|固定|取消固定|调用|写入|落地|美化|排版|格式化|润色|优化|排错|解决|处理|调整|恢复|回退|热补丁|对齐|不行|没效果|沒效果|老样子|老樣子|失败|失敗|错误|錯誤|报错|報錯|坏了|壞了|卡住|不回复|不回復|乱滑|亂滑|跑偏|套话|套話|敷衍|不实时|不即時|一股脑|一股腦)/i.test(compact);
}

function looksLikeMemoryWritePrompt(prompt: string): boolean {
  const text = prompt.trim();
  if (!text) return false;
  if (promptNeedsIdentityMemory(text)) return false;
  if (/(你记得|你記得|记得我什么|記得我什麼|关于我|我的记忆|我的記憶|what do you know|do you remember)/i.test(text)) return false;
  return /(记住|記住|记下来|記下來|加入记忆|写入记忆|长期记忆|長期記憶|以后都|下次记得|remember this|save this|store this|keep this preference|persist this|update memory|write memory)/i.test(text);
}

function isExecutableTtsPrompt(prompt: string): boolean {
  const text = prompt.trim();
  if (!text) return false;
  return /(朗读|读出来|读给我|念出来|语音读|播放朗读|开始朗读|暂停朗读|停止朗读|继续朗读|tts|read\s+aloud|speak\s+(this|current|selection)|stop\s+tts|pause\s+tts|resume\s+tts)/i.test(text);
}

function looksLikeCreateVaultFilePrompt(prompt: string): boolean {
  const text = prompt.trim();
  if (!text) return false;
  const compact = text.toLowerCase().replace(/[\s，。！？!?.、~～"'`]+/g, "");
  const hasCreateVerb = /(create|generate|write|make|new|建一个|建个|建一份|建份|新建|创建|建立|生成|写一个|写个|写一份|写份|做一个|做个|做一份|做份|弄一个|弄个)/i.test(compact);
  if (!hasCreateVerb) return false;
  const hasFileTarget = /(md|markdown|\.md|file|note|doc|document|笔记|文件|文档|文章|模板|语法|根目录|目录下|文件夹|路径|vault|库里|库中|库内)/i.test(compact);
  if (!hasFileTarget) return false;
  if (/(建议|建議|建立联系|建立關係|建立关系|怎么看|怎麼看|为什么|為什麼|是什么|是什麼|解释|说明|說明|如何|怎么|怎麼)/.test(compact) && !/(根目录|目录下|\.md|md|markdown|文件|笔记|文档|路径)/i.test(compact)) {
    return false;
  }
  return true;
}

function compactPromptForDedup(text: string): string {
  return text.replace(/\s+/g, "").trim().toLowerCase();
}

function samePromptForDedup(left: string, right: string): boolean {
  const a = compactPromptForDedup(left);
  const b = compactPromptForDedup(right);
  return Boolean(a) && a === b;
}

function promptContainsForDedup(haystack: string, needle: string): boolean {
  const target = compactPromptForDedup(needle);
  if (!target) return false;
  return compactPromptForDedup(haystack).includes(target);
}

function isInformationSeekingPrompt(prompt: string): boolean {
  const compact = prompt.trim().toLowerCase().replace(/[\s，。！？!?.、~～"'`]+/g, "");
  if (!compact) return false;
  if (promptNeedsIdentityMemory(prompt)) return true;
  return /(what|which|who|where|when|why|howmany|list|show|read|open|check|inspect|query|version|explain|summari[sz]e|analy[sz]e|status|tellme|inventory|哪些|那些|有啥|有什么|有什麼|有哪些|有那些|多少|几个|幾個|列出|清单|清單|列表|查看|看看|检查|查一下|读取|打开|是什么|是什麼|是多少|版本|版本号|版本號|什么意思|什麼意思|解释|說明|说明|总结|總結|分析|为什么|為什麼|原因|状态|狀態|情况|情況|装了哪些|裝了哪些|启用了哪些|啟用了哪些)/i.test(compact);
}

function hasFinalConclusion(content: string): boolean {
  return /(^|\n)\s*#{1,3}\s*(最终结论|Final conclusion|Final answer)\b/i.test(content)
    || /(^|\n)\s*(最终结论|Final conclusion|Final answer)\s*[:：]/i.test(content)
    || /(^|\n)\s*(改动\/读取的文件|改动的文件|Changed\/read files|Changed files)\s*[:：]/i.test(content)
    || (/(^|\n)\s*1[.、]\s+/.test(content) && /(^|\n)\s*(结果和提醒|结果|Result|Verification|Reminders)\s*[:：]/i.test(content));
}

function looksLikeHumanFinalAnswer(content: string): boolean {
  const text = stripStructuredChoices(stripProgrammaticRunStats(content).content)
    .replace(/\s+/g, " ")
    .trim();
  if (!text || text.length < 12) return false;
  if (isPromptishProgressNoteLine(text) || isOnlyRunStatsText(text)) return false;
  if (/^(?:执行中|已执行|失败|running|executed|failed)\b/i.test(text)) return false;
  return /(?:完成|已|修复|改动|验证|结果|结论|原因|需要|等待|阻塞|失败|成功|done|completed|changed|fixed|verified|result|blocked|failed)/i.test(text)
    || /(?:^|\n)\s*(?:1[.、]|[-*]\s+)/.test(content);
}

function classifyStaleRunningMessages(messages: Record<string, unknown>[]): {
  status: NonNullable<SessionHistoryEntry["status"]>;
  needsClosure: boolean;
  content: string;
  detail: string;
} {
  const assistantMessages = messages
    .filter((message) => message.role === "assistant" && typeof message.content === "string")
    .map((message) => String(message.content));
  const lastVisible = [...assistantMessages].reverse().find((content) => {
    const stripped = removeCancipActionBlocks(content)
      .replace(/<!--[\s\S]*?-->/g, "")
      .replace(/<details>[\s\S]*?<\/details>/gi, "")
      .trim();
    return stripped.length > 0 && !isProcessOnlySessionContent(content);
  });
  if (lastVisible && hasFinalConclusion(lastVisible)) {
    return {
      status: "completed",
      needsClosure: false,
      content: "",
      detail: "stale running session already had a final answer; marked completed"
    };
  }
  const readableRuns = extractReadableToolRunsFromMessages(messages);
  if (readableRuns.length) {
    return {
      status: "failed",
      needsClosure: true,
      content: "## 最终结论\n\n这条历史会话已停止运行；它留下了工具结果，但没有拿到模型最终回答。\n\n请点继续或重新发送原问题，Cancip 会基于最近工具结果接着处理。",
      detail: "stale running session had completed read-only tools but no final model answer; marked failed without synthetic answer"
    };
  }
  return {
    status: "failed",
    needsClosure: true,
    content: "## 最终结论\n\n这条会话不是还在执行，而是 Obsidian/Cancip 重载或切换会话后，请求被中断，历史状态卡在“运行中”。\n\n已自动把它收口为失败，避免继续转圈。原任务没有拿到最终模型回复，请重新发送或点继续后从最近工具结果接着做。",
    detail: "stale running session had no active request and no recoverable final answer; marked failed"
  };
}

function resumableTaskFromRawMessages(messages: Record<string, unknown>[], reason: "stopped" | "failed", detail = ""): ResumableTaskState | null {
  const user = [...messages].reverse().find((message) => message.role === "user" && typeof message.content === "string");
  const prompt = typeof user?.content === "string" ? user.content.trim() : "";
  if (!prompt || isTrivialChatPrompt(prompt)) return null;
  return { prompt: trimContext(prompt, 2000), reason, at: Date.now(), detail };
}

function isProcessOnlySessionContent(content: string): boolean {
  return isLegacyProgressStatusMessage(content);
}

function extractReadableToolRunsFromMessages(messages: Record<string, unknown>[]): ToolRun[] {
  const runs: ToolRun[] = [];
  for (const message of [...messages].reverse()) {
    const toolRuns = Array.isArray(message.toolRuns) ? message.toolRuns.filter(isRecord) : [];
    for (const item of toolRuns) {
      const action = parseCancipAction(item.action);
      if (!action || !isReadOnlyAction(action)) continue;
      if (item.status !== "executed" || typeof item.result !== "string" || !item.result.trim()) continue;
      runs.push({
        id: typeof item.id === "string" && item.id ? item.id : crypto.randomUUID(),
        action,
        summary: typeof item.summary === "string" && item.summary ? item.summary : describeActionPlain(action),
        status: "executed",
        createdAt: typeof item.createdAt === "string" ? item.createdAt : new Date().toISOString(),
        startedAt: typeof item.startedAt === "string" ? item.startedAt : undefined,
        executedAt: typeof item.executedAt === "string" ? item.executedAt : undefined,
        result: item.result
      });
    }
    if (runs.length) return runs;
  }
  for (const message of [...messages].reverse()) {
    if (typeof message.content !== "string") continue;
    const recovered = recoverToolRunsFromMessageContent(message.content);
    if (recovered.length) return recovered;
  }
  return [];
}

function recoverToolRunsFromMessageContent(content: string): ToolRun[] {
  const runs: ToolRun[] = [];
  const blocks = content
    .split(/\n\n(?=(?:read|command)\s+[^\n\r]+\r?\n)/i)
    .map((block) => block.trim())
    .filter(Boolean);
  for (const block of blocks) {
    const read = block.match(/^read\s+([^\n\r]+)\r?\n([\s\S]*)$/i);
    if (read) {
      const path = read[1]?.trim();
      const result = read[2]?.trim();
      if (!path || !result) continue;
      const action: CancipAction = { type: "read", path };
      runs.push({
        id: crypto.randomUUID(),
        action,
        summary: describeActionPlain(action),
        status: "executed",
        createdAt: new Date().toISOString(),
        result: `read ${path}\n${result}`
      });
      continue;
    }
    const commandMatch = block.match(/^command\s+([^\n\r]+)\r?\n([\s\S]*)$/i);
    if (!commandMatch) continue;
    const command = commandMatch[1]?.trim();
    const result = commandMatch[2]?.trim();
    if (!command || !result) continue;
    const action: CancipAction = { type: "command", command };
    if (!isReadOnlyAction(action)) continue;
    runs.push({
      id: crypto.randomUUID(),
      action,
      summary: describeActionPlain(action),
      status: "executed",
      createdAt: new Date().toISOString(),
      result: `command ${command}\n${result}`
    });
  }
  return runs;
}

function usefulResultLines(result: string): string[] {
  return result
    .split(/\r?\n/)
    .map((line) => line.trimEnd())
    .filter((line) => {
      const trimmed = line.trim();
      if (!trimmed) return false;
      if (/^(read|command)\s+[^\n]+$/i.test(trimmed)) return false;
      return true;
    })
    .map((line) => trimContext(redactSensitiveText(line), 220));
}

function describeActionPlain(action: CancipAction): string {
  if (action.type === "read") return `read ${action.path}`;
  if (action.type === "command") return `command ${action.command}`;
  if (action.type === "todo") return `todo ${action.op}`;
  if (action.type === "automation") return `automation ${action.op}`;
  if (action.type === "config") return `config ${action.path?.trim() || CANCIP_CONFIG_PATH}`;
  if (action.type === "write") return `write ${action.path}`;
  if (action.type === "append") return `append ${action.path}`;
  if (action.type === "patch") return `patch ${action.path}`;
  if (action.type === "mkdir") return `mkdir ${action.path}`;
  if (action.type === "rename") return `rename ${action.path} -> ${action.newPath}`;
  if (action.type === "move") return `move ${action.path} -> ${action.newPath}`;
  if (action.type === "delete") return `delete ${action.path}`;
  return `copy ${action.path} -> ${action.newPath}`;
}

function formatInstalledPluginsSummary(plugins: InstalledPluginInfo[], enabledCount: number, includeDisabled: boolean): string {
  if (!plugins.length) {
    return "没有在 Obsidian 社区插件启用列表里找到已启用社区插件。";
  }
  const title = includeDisabled
    ? `已启用 ${enabledCount} 个；插件目录共 ${plugins.length} 个`
    : `已启用 ${enabledCount} 个`;
  const lines = plugins.map((plugin, index) => {
    const state = plugin.enabled ? "" : " [未启用]";
    const version = plugin.version ? ` v${plugin.version}` : "";
    const manifest = plugin.manifestFound ? "" : " [缺 manifest]";
    const error = plugin.error ? ` [manifest 读取失败: ${trimContext(plugin.error, 80)}]` : "";
    const name = plugin.name && plugin.name !== plugin.id ? `${plugin.name} (${plugin.id})` : plugin.id;
    return `${index + 1}. ${name}${version}${state}${manifest}${error}`;
  });
  return `${title}：\n\n${lines.join("\n")}`;
}

function countVaultOverviewKinds(files: TFile[]): Record<string, number> {
  const result: Record<string, number> = {
    markdown: 0,
    pdf: 0,
    image: 0,
    office: 0,
    canvas: 0,
    text: 0,
    other: 0
  };
  for (const file of files) {
    const extension = file.extension.toLowerCase();
    if (isMarkdownFile(file)) result.markdown += 1;
    else if (isPdfFile(file)) result.pdf += 1;
    else if (isImagePath(file.path)) result.image += 1;
    else if (/^(docx?|xlsx?|pptx?|ods|csv)$/i.test(extension)) result.office += 1;
    else if (extension === "canvas" || extension === "base") result.canvas += 1;
    else if (isContextTextFile(file)) result.text += 1;
    else result.other += 1;
  }
  return result;
}

function countVaultOverviewExtensions(files: TFile[]): Array<[string, number]> {
  const counts = new Map<string, number>();
  for (const file of files) {
    const extension = file.extension.toLowerCase() || "(none)";
    counts.set(extension, (counts.get(extension) ?? 0) + 1);
  }
  return [...counts.entries()].sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]));
}

function isVaultOverviewUserFacingPath(path: string, obsidianConfigDir: string): boolean {
  const normalized = normalizePath(path);
  if (!normalized) return false;
  if (isPathInFolder(normalized, obsidianConfigDir)) return false;
  if (normalized.startsWith(".cancip/")) return false;
  if (normalized.startsWith(".trash/")) return false;
  if (normalized.startsWith("AI/Cancip/Exports/")) return false;
  if (normalized.startsWith("AI/Cancip/Review/")) return false;
  return true;
}

function timestampMs(value: unknown, fallback = Date.now()): number {
  if (typeof value === "number" && Number.isFinite(value)) return value;
  if (typeof value === "string") {
    const parsed = Date.parse(value);
    if (Number.isFinite(parsed)) return parsed;
    const numeric = Number(value);
    if (Number.isFinite(numeric)) return numeric;
  }
  return fallback;
}

function formatElapsed(ms: number): string {
  const safe = Math.max(0, Math.round(ms));
  if (safe < 1000) return `${safe}ms`;
  const seconds = Math.round(safe / 1000);
  if (seconds < 60) return `${seconds}s`;
  const minutes = Math.floor(seconds / 60);
  const rest = seconds % 60;
  return `${minutes}m${String(rest).padStart(2, "0")}s`;
}

function shouldNeedMoreActionAfterToolRuns(runs: ToolRun[]): boolean {
  if (!runs.length) return true;
  const active = runs.filter((run) => run.status === "executed" || run.status === "failed");
  if (!active.length) return false;
  if (active.some((run) => run.status === "failed")) return true;
  if (active.every((run) => isLowCommitmentAction(run.action))) return true;
  return hasUnverifiedWriteAction(active);
}

function shouldNeedMoreActionForPrompt(prompt: string, runs: ToolRun[]): boolean {
  if (classifyPromptIntent(prompt) !== "implementation") return false;
  const requiresStateChange = promptRequiresStateChange(prompt);
  if (shouldNeedMoreActionAfterToolRuns(runs)) return requiresStateChange || runs.some((run) => run.status === "failed");
  const lower = prompt.toLowerCase();
  const isUiOrPluginTask = /(settings?\s*(page|tab|ui)|ui|interface|button|model\s*options?|model\s*management|设置页|设置中|界面|按钮|可选模型|模型管理|插件|自身|自己)/i.test(lower);
  if (!isUiOrPluginTask) return false;
  const active = runs.filter((run) => run.status === "executed");
  const writePaths = uniqueStrings(active
    .filter((run) => isWriteActionForContinuation(run.action))
    .map((run) => actionVerificationPath(run.action))
    .filter(Boolean));
  if (!writePaths.length) return true;
  if (!hasUnverifiedWriteAction(active)) return false;
  const hasPluginWrite = writePaths.some((path) => path.includes("/plugins/cancip/"));
  if (hasPluginWrite) return false;
  return writePaths.every((path) => path === ".cancip/config.json" || path.startsWith(".cancip/"));
}

function activeFilePathFromToolRuns(runs: ToolRun[]): string {
  for (const run of [...runs].reverse()) {
    if (run.status !== "executed") continue;
    if (run.action.type !== "command" || run.action.command.trim() !== "obsidian.currentView") continue;
    const match = (run.result ?? "").match(/^activeFile:\s*(.+)$/m);
    const path = match?.[1]?.trim();
    if (path) return normalizePath(path);
  }
  return "";
}

function promptRequiresStateChange(prompt: string): boolean {
  const compact = prompt.trim().toLowerCase().replace(/[\s，。！？!?.、~～"'`]+/g, "");
  if (!compact) return false;
  if (isExecutableTtsPrompt(prompt)) return true;
  if (looksLikeCreateVaultFilePrompt(prompt)) return true;
  return /(add|implement|change|modify|update|delete|move|rename|create|install|restart|build|execute|patch|write|format|polish|restore|rollback|hot.?patch|run|apply|save|commit|release|publish|configure|加|新增|添加|补|改|修改|更新|修复|修好|修一下|删|删除|移动|重命名|新建|创建|建立|生成|安装|装好|重启|构建|执行|运行|打开|开启|写入|写|落地|美化|排版|格式化|润色|调整|恢复|回退|热补丁|保存|提交|发布|配置|设置|应用|弄好|做出来|做成)/i.test(compact);
}

function shouldContinueToolLoopFromRuns(runs: ToolRun[]): boolean {
  if (!runs.length) return false;
  if (runs.some((run) => run.status === "pending" || run.status === "executing" || run.status === "blocked")) return false;
  if (runs.some((run) => run.status === "failed" || run.status === "rejected")) return true;
  const executed = runs.filter((run) => run.status === "executed");
  if (!executed.length) return false;
  if (executed.every((run) => isLowCommitmentAction(run.action))) return false;
  return hasUnverifiedWriteAction(executed);
}

function hasUnverifiedWriteAction(runs: ToolRun[]): boolean {
  const writePaths = uniqueStrings(runs
    .filter((run) => run.status === "executed" && isWriteActionForContinuation(run.action))
    .map((run) => actionVerificationPath(run.action))
    .filter(Boolean));
  if (!writePaths.length) return false;
  if (runs.some((run) => run.status === "executed" && isSelfVerifyingAction(run.action, writePaths))) return false;
  return !runs.some((run) => run.status === "executed" && isVerificationAction(run.action, writePaths));
}

function isWriteActionForContinuation(action: CancipAction): boolean {
  if (action.type === "write" || action.type === "append" || action.type === "patch" || action.type === "mkdir" || action.type === "rename" || action.type === "move" || action.type === "copy" || action.type === "delete") return true;
  if (action.type === "config") return true;
  if (action.type === "todo") return action.op !== "list";
  if (action.type === "automation") return action.op !== "list";
  if (action.type !== "command") return false;
  return !isLowCommitmentAction(action);
}

function actionVerificationPath(action: CancipAction): string {
  if (action.type === "rename" || action.type === "move" || action.type === "copy") return normalizePath(action.newPath);
  if (action.type === "config") return normalizePath(action.path?.trim() || CANCIP_CONFIG_PATH);
  if ("path" in action && typeof action.path === "string") return normalizePath(action.path);
  if (action.type === "command") return action.command.trim();
  if (action.type === "automation") return action.id?.trim() || "automation";
  return "";
}

function isSelfVerifyingAction(action: CancipAction, writePaths: string[]): boolean {
  if (action.type === "write" || action.type === "append" || action.type === "delete") {
    const path = normalizePath(action.path);
    return writePaths.some((target) => target === path);
  }
  if (action.type === "rename" || action.type === "move") {
    const newPath = normalizePath(action.newPath);
    return writePaths.some((target) => target === newPath);
  }
  if (action.type === "config") {
    const path = normalizePath(action.path?.trim() || CANCIP_CONFIG_PATH);
    return writePaths.some((target) => target === path);
  }
  return false;
}

function isVerificationAction(action: CancipAction, writePaths: string[]): boolean {
  if (action.type === "config") {
    const path = normalizePath(action.path?.trim() || CANCIP_CONFIG_PATH);
    return writePaths.some((target) => target === path);
  }
  if (action.type === "read") {
    const path = normalizePath(action.path);
    return writePaths.some((target) => target === path || target.startsWith("command:"));
  }
  if (action.type !== "command") return false;
  const command = action.command.trim();
  if (command === "cancip.searchVault" || command === "cancip.previewVaultSearch") return true;
  return writePaths.some((target) => target === command);
}

function isLowCommitmentAction(action: CancipAction): boolean {
  if (action.type === "read") return true;
  if (action.type === "todo") return true;
  if (action.type === "automation") return action.op === "list";
  if (action.type !== "command") return false;
  return new Set([
    "obsidian.listCommands",
    "obsidian.currentView",
    "obsidian.dom.snapshot",
    "obsidian.ui.buttons",
    "obsidian.ui.buttonRules",
    "obsidian.tags",
    "obsidian.tabs",
    "cancip.tools.index",
    "cancip.tools.help",
    "web.search",
    "web.fetch",
    "cancip.reviewGate.list",
    "cancip.sessionEvents",
    "cancip.sessionHistory",
    "cancip.subagents.list",
    "cancip.subagents.status",
    "cancip.subagents.open",
    "cancip.installedPlugins",
    "cancip.pluginCapabilities",
    "cancip.pluginRoute",
    "cancip.annotate.help",
    "cancip.study.help",
    "cancip.skills.list",
    "cancip.skills.read",
    "cancip.experience.list",
    "cancip.experience.harvest",
    "cancip.attachment.help",
    "cancip.tts.help",
    "cancip.tts.probe",
    "cancip.tts.voices",
    "cancip.tts.status",
    "cancip.externalFiles.help",
    "cancip.findTarget",
    "cancip.searchVault",
    "cancip.previewVaultSearch",
    "cancip.newsBrief",
    "cancip.vaultDailyReport",
    "cancip.automation.templates",
    "cancip.automation.list",
    "github.help",
    "github.status",
    "github.repo",
    "github.issues",
    "github.pulls",
    "github.releases",
    "github.workflowRuns",
    "github.branches",
    "github.file"
  ]).has(action.command.trim());
}

function removeCancipActionBlocks(content: string): string {
  return removeLooseCancipActionJson(content
    .replace(/```cancip-action\s*[\s\S]*?```/gi, "\n\n")
    .replace(/<cancip-action\b[^>]*>[\s\S]*?<\/cancip-action>/gi, "\n\n")
  ).replace(/\n{3,}/g, "\n\n");
}

function isRepairSlashCommand(input: string): boolean {
  const normalized = input.trim().toLowerCase();
  return normalized === "/修复" || normalized === "/fix" || normalized === "/repair";
}

function looksLikePathQuery(input: string): boolean {
  return /(^|[\s"'`])\.?[A-Za-z0-9_\-\u4e00-\u9fff]+[/\\][^\s"'`]+/.test(input) || /\.[A-Za-z0-9]{2,6}($|[\s"'`，。；,;])/.test(input);
}

function shouldScanHiddenForQuery(query: string): boolean {
  const lower = query.toLowerCase().trim();
  return lower.startsWith(".") || lower.includes("obsidian") || lower.includes("cancip") || lower.includes("config") || lower.includes("plugin") || lower.includes("插件") || lower.includes("配置");
}

function hiddenMentionFoldersForQuery(query: string, obsidianConfigDir: string): string[] {
  const lower = query.toLowerCase();
  if (lower.includes("obsidian") || lower.includes("plugin") || lower.includes("插件")) return [obsidianConfigDir];
  if (lower.includes(".cancip") || lower.includes("cancip") || lower.includes("config") || lower.includes("配置")) return [".cancip", obsidianConfigDir];
  return [obsidianConfigDir, ".cancip"];
}

function scoreSearchCandidate(file: VaultTextFile, tokens: string[]): number {
  const text = `${file.basename}\n${file.path}`.toLowerCase();
  let score = 0;
  for (const token of tokens) {
    if (file.basename.toLowerCase() === token) score += 100;
    if (file.basename.toLowerCase().includes(token)) score += 20;
    if (text.includes(token)) score += 8;
  }
  if (file.path.startsWith("AI/Cancip/Memory/")) score += 6;
  if (file.loaded) score += 2;
  return score;
}

function scoreSearchText(path: string, title: string, content: string, tokens: string[]): number {
  const haystack = `${title}\n${path}\n${content}`.toLowerCase();
  let score = 0;
  for (const token of tokens) {
    const escaped = escapeRegExp(token);
    const matches = haystack.match(new RegExp(escaped, "g"));
    if (matches) score += matches.length;
    if (title.toLowerCase().includes(token)) score += 4;
    if (path.toLowerCase().includes(token)) score += 2;
  }
  return score;
}

function scoreVaultTargetPath(path: string, title: string, kind: TargetCandidateKind, query: string, tokens: string[]): number {
  const normalizedPath = normalizePath(path);
  const field = `${title}\n${normalizedPath}\n${normalizedPath.split("/").join(" ")}`.toLowerCase();
  const compactField = field.replace(/[^a-z0-9\u4e00-\u9fff]+/g, "");
  const q = query.toLowerCase().trim();
  const compactQuery = q.replace(/[^a-z0-9\u4e00-\u9fff]+/g, "");
  let score = 0;
  if (q && title.toLowerCase() === q) score += 320;
  if (q && normalizedPath.toLowerCase() === q) score += 340;
  if (compactQuery && title.toLowerCase().replace(/[^a-z0-9\u4e00-\u9fff]+/g, "") === compactQuery) score += 260;
  if (compactQuery && compactField.includes(compactQuery)) score += 180;
  if (compactQuery.length >= 3 && isSubsequence(compactQuery, compactField)) score += 48;
  const pathParts = normalizedPath.toLowerCase().split(/[/._\s-]+/).filter(Boolean);
  const titleLower = title.toLowerCase();
  for (const token of tokens) {
    if (!token) continue;
    if (titleLower === token) score += 120;
    if (pathParts.some((part) => part === token)) score += 80;
    if (titleLower.startsWith(token)) score += 64;
    if (titleLower.includes(token)) score += 42;
    if (normalizedPath.toLowerCase().includes(token)) score += 26;
    const bestSimilarity = Math.max(
      normalizedSimilarity(token, titleLower),
      ...pathParts.slice(-5).map((part) => normalizedSimilarity(token, part))
    );
    if (bestSimilarity >= 0.78) score += Math.round(40 * bestSimilarity);
  }
  if (kind === "folder") score += 8;
  if (kind === "attachment" && (isPdfPath(normalizedPath) || isImagePath(normalizedPath))) score += 10;
  return score;
}

function uniqueTargetCandidates(candidates: TargetCandidate[]): TargetCandidate[] {
  const seen = new Map<string, TargetCandidate>();
  for (const candidate of candidates) {
    const key = `${candidate.kind}:${normalizePath(candidate.path)}`;
    const previous = seen.get(key);
    if (!previous || candidate.score > previous.score) seen.set(key, candidate);
  }
  return [...seen.values()];
}

function kindRank(kind: TargetCandidateKind): number {
  if (kind === "content") return 0;
  if (kind === "file") return 1;
  if (kind === "folder") return 2;
  if (kind === "command") return 3;
  if (kind === "attachment-content") return 4;
  return 5;
}

function memoryFilePriority(path: string, prompt = ""): number {
  const name = path.split("/").pop() ?? "";
  const order = promptNeedsIdentityMemory(prompt) ? [
    "PROFILE.md",
    "USER_PREFERENCES_QUICK.md",
    "PREFERENCES.md",
    "CANCIP_INDEX.md",
    "PROJECTS.md",
    "WORKFLOWS.md",
    "TOOLS.md",
    "SKILLS.md",
    "obsidian-整理偏好.md",
    "INDEX.md",
    "NOTIFICATIONS.md",
    "TRADING.md",
    "C-DEPENDENCY-MIGRATION.md",
    "README.md"
  ] : [
    "CANCIP_INDEX.md",
    "USER_PREFERENCES_QUICK.md",
    "PREFERENCES.md",
    "PROJECTS.md",
    "WORKFLOWS.md",
    "TOOLS.md",
    "SKILLS.md",
    "PROFILE.md",
    "obsidian-整理偏好.md",
    "INDEX.md",
    "NOTIFICATIONS.md",
    "TRADING.md",
    "C-DEPENDENCY-MIGRATION.md",
    "README.md"
  ];
  const index = order.indexOf(name);
  return index >= 0 ? index : 100;
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => window.setTimeout(resolve, ms));
}

function withTimeout<T>(promise: Promise<T>, timeoutMs: number, message: string): Promise<T> {
  let timeoutId: number | undefined;
  const timeout = new Promise<never>((_, reject) => {
    timeoutId = window.setTimeout(() => reject(new Error(message)), timeoutMs);
  });
  return Promise.race([promise, timeout]).finally(() => {
    if (timeoutId !== undefined) window.clearTimeout(timeoutId);
  });
}

function headerValue(headers: Record<string, string> | undefined, name: string): string {
  if (!headers) return "";
  const direct = headers[name] ?? headers[name.toLowerCase()] ?? headers[name.toUpperCase()];
  if (typeof direct === "string") return direct.trim();
  const lower = name.toLowerCase();
  const hit = Object.entries(headers).find(([key]) => key.toLowerCase() === lower);
  return typeof hit?.[1] === "string" ? hit[1].trim() : "";
}

function modelRetryAfterMsFromReason(reason: string): number | null {
  const text = reason.trim();
  if (!text) return null;
  const retryAfterMatch = text.match(/\bretry[-_ ]?after\b["'\s:=]+([^"',;\s}]+)/i);
  if (retryAfterMatch) {
    const parsed = retryDelayTokenToMs(retryAfterMatch[1]);
    if (parsed !== null) return parsed;
  }
  const retryAfterMsMatch = text.match(/\bretry[-_ ]?after[-_ ]?ms\b["'\s:=]+(\d{2,7})\b/i);
  if (retryAfterMsMatch) {
    const value = Number(retryAfterMsMatch[1]);
    if (Number.isFinite(value) && value > 0) return value;
  }
  const bodyJson = parseFirstJsonObject(text);
  const parsed = retryAfterMsFromJson(bodyJson);
  return parsed;
}

function retryDelayTokenToMs(value: string): number | null {
  const token = value.trim().replace(/^["']|["']$/g, "");
  if (!token) return null;
  const numeric = Number(token);
  if (Number.isFinite(numeric) && numeric > 0) return Math.round(numeric * 1000);
  const dateMs = Date.parse(token);
  if (Number.isFinite(dateMs)) return Math.max(0, dateMs - Date.now());
  return null;
}

function retryAfterMsFromJson(value: unknown): number | null {
  if (!isRecord(value)) return null;
  const candidates = [
    value.retry_after_ms,
    value.retryAfterMs,
    value.retry_after,
    value.retryAfter,
    isRecord(value.error) ? value.error.retry_after_ms : undefined,
    isRecord(value.error) ? value.error.retryAfterMs : undefined,
    isRecord(value.error) ? value.error.retry_after : undefined,
    isRecord(value.error) ? value.error.retryAfter : undefined
  ];
  for (const candidate of candidates) {
    if (typeof candidate === "number" && Number.isFinite(candidate) && candidate > 0) {
      return candidate > 1000 ? Math.round(candidate) : Math.round(candidate * 1000);
    }
    if (typeof candidate === "string") {
      const parsed = retryDelayTokenToMs(candidate);
      if (parsed !== null) return parsed;
    }
  }
  return null;
}

function isRateLimitRetryReason(reason: string): boolean {
  return /(?:HTTP\s*429|\b429\b|rate[-_\s]?limit|too\s+many\s+requests|requests\s+per\s+(?:minute|day)|tokens\s+per\s+(?:minute|day)|quota|retry[-_ ]?after)/i.test(reason);
}

function isServiceRetryReason(reason: string): boolean {
  return isRateLimitRetryReason(reason)
    || /(?:HTTP\s*(?:408|425|500|502|503|504|529)\b|\b(?:408|425|500|502|503|504|529)\b|timeout|timed\s*out|temporarily\s+unavailable|overloaded|server\s+busy|upstream|gateway|connection\s+(?:reset|closed|aborted)|network\s+error|econnreset|etimedout)/i.test(reason);
}

function resolveLanguage(mode: LanguageMode): Language {
  if (isLanguage(mode)) return mode;
  return resolveLocaleLanguage(navigator.language || "en");
}

function resolveLocaleLanguage(locale: string): Language {
  const normalized = locale.toLowerCase();
  if (normalized.startsWith("zh")) {
    return normalized.includes("tw") || normalized.includes("hk") || normalized.includes("mo") || normalized.includes("hant")
      ? "zh-TW"
      : "zh";
  }
  if (normalized.startsWith("ug")) return "ug";
  if (normalized.startsWith("tr")) return "tr";
  if (normalized.startsWith("ru")) return "ru";
  if (normalized.startsWith("ja")) return "ja";
  if (normalized.startsWith("ko")) return "ko";
  if (normalized.startsWith("es")) return "es";
  if (normalized.startsWith("fr")) return "fr";
  if (normalized.startsWith("de")) return "de";
  if (normalized.startsWith("ar")) return "ar";
  return "en";
}

function languageSelectOptions(autoLabel: string): Record<LanguageMode, string> {
  return {
    auto: autoLabel,
    zh: LANGUAGE_LABELS.zh,
    "zh-TW": LANGUAGE_LABELS["zh-TW"],
    en: LANGUAGE_LABELS.en,
    ug: LANGUAGE_LABELS.ug,
    tr: LANGUAGE_LABELS.tr,
    ru: LANGUAGE_LABELS.ru,
    ja: LANGUAGE_LABELS.ja,
    ko: LANGUAGE_LABELS.ko,
    es: LANGUAGE_LABELS.es,
    fr: LANGUAGE_LABELS.fr,
    de: LANGUAGE_LABELS.de,
    ar: LANGUAGE_LABELS.ar
  };
}

function isChineseLanguage(language: Language): boolean {
  return language === "zh" || language === "zh-TW";
}

function isTtsProvider(value: unknown): value is TtsProvider {
  return value === "auto"
    || value === "builtin-prime-tts"
    || value === "android-system"
    || value === "web-speech"
    || value === "custom-url";
}

function isTtsQualityMode(value: unknown): value is TtsQualityMode {
  return value === "quality-first";
}

function defaultTtsVoiceForLanguage(lang: string): string {
  const lower = lang.toLowerCase();
  if (lower.startsWith("zh-tw")) return "zh-TW-HsiaoChenNeural";
  if (lower.startsWith("zh")) return "zh-CN-XiaoxiaoNeural";
  if (lower.startsWith("ja")) return "ja-JP-NanamiNeural";
  if (lower.startsWith("ko")) return "ko-KR-SunHiNeural";
  if (lower.startsWith("fr")) return "fr-FR-DeniseNeural";
  if (lower.startsWith("de")) return "de-DE-KatjaNeural";
  if (lower.startsWith("es")) return "es-ES-ElviraNeural";
  if (lower.startsWith("ru")) return "ru-RU-SvetlanaNeural";
  if (lower.startsWith("tr")) return "tr-TR-EmelNeural";
  if (lower.startsWith("ar")) return "ar-SA-ZariyahNeural";
  return "en-US-AvaMultilingualNeural";
}

function base64ToArrayBuffer(input: string): ArrayBuffer {
  const clean = input.includes(",") ? input.split(",").pop() ?? "" : input;
  const binary = atob(clean.replace(/\s+/g, ""));
  const bytes = new Uint8Array(binary.length);
  for (let index = 0; index < binary.length; index += 1) {
    bytes[index] = binary.charCodeAt(index);
  }
  return bytes.buffer;
}

function parsePrimeTtsMeta(text: string): PrimeTtsMeta {
  const raw = JSON.parse(text) as unknown;
  if (!isRecord(raw)) throw new Error("PrimeTTS meta.json is not an object");
  const sampleRate = Number(raw.sample_rate);
  const absFrameBins = Number(raw.abs_frame_bins);
  const maxFrames = Number(raw.max_frames);
  if (!Number.isFinite(sampleRate) || !Number.isFinite(absFrameBins) || !Number.isFinite(maxFrames)) {
    throw new Error("PrimeTTS meta.json is missing numeric sample_rate/abs_frame_bins/max_frames");
  }
  return { sample_rate: sampleRate, abs_frame_bins: absFrameBins, max_frames: maxFrames };
}

